///////\n\nmodel Employees {\n  id          Int @id @default(autoincrement())\n  warehouseId Int\n\n  name     String\n  email    String  @unique\n  phone    String?\n  password String\n  status   Int?\n\n  createdAt DateTime  @default(now())\n  updateAt  DateTime?\n\n  warehouse Warehouse @relation(fields: [warehouseId], references: [id])\n}\n\n////////////////////////////\n/// CATEGORY\n////////////////////////////\n\nmodel Categories {\n  id          Int    @id @default(autoincrement())\n  name        String\n  description String\n  status      Int\n  hot         Int\n\n  createdAt DateTime  @default(now())\n  updateAt  DateTime?\n\n  products Products[]\n}\n\n////////////////////////////\n/// PRODUCTS\n////////////////////////////\n\nmodel Products {\n  id Int @id @default(autoincrement())\n\n  categoryId Int\n  category   Categories @relation(fields: [categoryId], references: [id])\n\n  name        String\n  description String\n\n  rate      Int\n  countRate Int\n  purchases Int\n\n  createdAt DateTime  @default(now())\n  updateAt  DateTime?\n\n  productTypes ProductDetails[]\n  comments     Comments[]\n}\n\n////////////////////////////\n/// PRODUCT DETAILS (SIZE COLOR)\n////////////////////////////\n\nmodel ProductDetails {\n  id Int @id @default(autoincrement())\n\n  productId Int\n  color     Int\n  size      Int\n  price     Int\n\n  status Int\n\n  createdAt DateTime  @default(now())\n  updateAt  DateTime?\n\n  product Products @relation(fields: [productId], references: [id])\n\n  productStock ProductStock[]\n  orderDetail  OrderDetails[]\n  cartItems    CartItems[]\n\n  @@unique([productId, size, color])\n}\n\n////////////////////////////\n/// STOCK\n////////////////////////////\n\nmodel ProductStock {\n  id Int @id @default(autoincrement())\n\n  productDetailId Int\n  warehouseId     Int\n\n  quantity Int\n\n  productDetail ProductDetails @relation(fields: [productDetailId], references: [id])\n  warehouse     Warehouse      @relation(fields: [warehouseId], references: [id])\n\n  @@unique([productDetailId, warehouseId])\n}\n\n////////////////////////////\n/// COMMENT\n////////////////////////////\n\nmodel Comments {\n  id Int @id @default(autoincrement())\n\n  userId    Int\n  productId Int\n\n  content String\n\n  createdAt DateTime  @default(now())\n  updateAt  DateTime?\n\n  user    Customers @relation(fields: [userId], references: [id])\n  product Products  @relation(fields: [productId], references: [id])\n}\n\n////////////////////////////\n/// CART\n////////////////////////////\n\nmodel Cart {\n  id Int @id @default(autoincrement())\n\n  customerId Int @unique\n\n  customer Customers @relation(fields: [customerId], references: [id])\n\n  items CartItems[]\n}\n\nmodel CartItems {\n  id Int @id @default(autoincrement())\n\n  cartId          Int\n  productDetailId Int\n  quantity        Int\n\n  cart          Cart           @relation(fields: [cartId], references: [id])\n  productDetail ProductDetails @relation(fields: [productDetailId], references: [id])\n\n  @@unique([cartId, productDetailId])\n}\n\n////////////////////////////\n/// ORDER\n////////////////////////////\n\nmodel Orders {\n  id Int @id @default(autoincrement())\n\n  customerId Int\n  status     Int\n  totalPrice Int\n\n  createdAt DateTime @default(now())\n\n  customer Customers @relation(fields: [customerId], references: [id])\n\n  orderDetails OrderDetails[]\n}\n\n////////////////////////////\n/// ORDER DETAILS\n////////////////////////////\n\nmodel OrderDetails {\n  id Int @id @default(autoincrement())\n\n  orderId         Int\n  productDetailId Int\n\n  quantity Int\n  price    Int\n\n  order         Orders         @relation(fields: [orderId], references: [id])\n  productDetail ProductDetails @relation(fields: [productDetailId], references: [id])\n}\n",
